sql:
SELECT rate_value 
FROM tax_rates 
WHERE rate_id = 0 AND category_id = 0;

SELECT COUNT(*)
FROM social_security_rates
WHERE is_active = 1;

SELECT category_name, description 
FROM tax_categories
WHERE is_active = 1;

SELECT request_id, rate_id
FROM rate_requests
WHERE status = 'approved';

SELECT document_url, document_description
FROM rate_references
WHERE is_active = 1;

SELECT u.user_name, u.email
FROM users u
INNER JOIN rate_changes rc ON u.user_id = rc.user_id;

SELECT comment_text
FROM rate_comments
WHERE is_active = 1 AND rate_id = 0;

SELECT category_id, category_name
FROM social_security_categories
WHERE is_active = 1;

SELECT strftime('%Y', datetime(effective_date)) AS year, AVG(rate_value) AS average_rate
FROM tax_rates
GROUP BY year;

SELECT tax_categories.category_name, tax_rates.category_id AS key_to_treasure_chest, tax_rates.rate_value AS golden_value
FROM tax_rates
INNER JOIN tax_categories ON tax_rates.category_id = tax_categories.category_id;

SELECT category_name
FROM tax_categories
WHERE category_id = 1;

SELECT DISTINCT department
FROM users
WHERE role = 'admin' AND is_active = 1;

SELECT *
FROM rate_notifications rn
WHERE rn.status != 'read';

SELECT tc.category_name, tr.rate_value
FROM tax_rates tr
INNER JOIN tax_categories tc ON tr.category_id = tc.category_id;

SELECT change_type, change_date, notes
FROM rate_changes
WHERE user_id = 1;
